135	// RoutingConfig is the agent routing policy block. See FEAT-006 Profile
136	// Routing and epic ddx-bbb65768. ProfilePriority is the legacy flat list
137	// and is deprecated in favour of ProfileLadders (per-profile tier lists).
138	// When both are present, ProfileLadders wins.
139	type RoutingConfig struct {
140		// ProfilePriority is the deprecated flat-list form. New configs should
141		// use ProfileLadders.
142		ProfilePriority []string `yaml:"profile_priority,omitempty" json:"profile_priority,omitempty"`
143		// ProfileLadders maps a profile name to the ordered tier list that a
144		// dispatch should try. Example:
145		//   default: [cheap, standard, smart]
146		//   cheap:   [cheap]
147		//   fast:    [fast, smart]
148		//   smart:   [smart]
149		ProfileLadders map[string][]string `yaml:"profile_ladders,omitempty" json:"profile_ladders,omitempty"`
150		// DefaultHarness is the fallback harness when no profile match succeeds.
151		DefaultHarness string `yaml:"default_harness,omitempty" json:"default_harness,omitempty"`
152		// ModelOverrides maps a profile name to a concrete model reference.
153		// e.g. { "cheap": "qwen/qwen3.6", "smart": "claude-opus-4-6" }.
154		ModelOverrides map[string]string `yaml:"model_overrides,omitempty" json:"model_overrides,omitempty"`
155	}
