164	// DefaultProfileLadders returns the built-in profile escalation policy.
165	func DefaultProfileLadders() map[string][]string {
166		out := make(map[string][]string, len(defaultProfileLadders))
167		for profile, ladder := range defaultProfileLadders {
168			out[profile] = append([]string(nil), ladder...)
169		}
170		return out
171	}
172	
173	// ResolvedLadder returns the escalation ladder for the named profile. If
174	// ProfileLadders contains an entry for profile, that wins. Otherwise falls
175	// back to the deprecated ProfilePriority for the default profile only. If
176	// neither is set, returns the shipped FEAT-006 profile ladder.
177	func (r *RoutingConfig) ResolvedLadder(profile string) []string {
178		if profile == "" {
179			profile = "default"
180		}
181		if r == nil {
182			if ladder, ok := defaultProfileLadders[profile]; ok {
183				return append([]string(nil), ladder...)
184			}
185			return append([]string(nil), defaultProfileLadders["default"]...)
186		}
187		if r.ProfileLadders != nil {
188			if ladder, ok := r.ProfileLadders[profile]; ok && len(ladder) > 0 {
189				return append([]string(nil), ladder...)
190			}
191		}
192		if profile == "default" && len(r.ProfilePriority) > 0 {
193			return append([]string(nil), r.ProfilePriority...)
194		}
195		if ladder, ok := defaultProfileLadders[profile]; ok {
196			return append([]string(nil), ladder...)
197		}
198		return append([]string(nil), defaultProfileLadders["default"]...)
199	}
