11	// TestResolveEvidenceCaps_DefaultsWhenNil verifies that an empty config
12	// resolves to the built-in defaults.
13	func TestResolveEvidenceCaps_DefaultsWhenNil(t *testing.T) {
14		c := &NewConfig{Version: "1.0"}
15		got := c.ResolveEvidenceCaps("any")
16		want := evidence.DefaultCaps()
17		if got != want {
18			t.Errorf("default caps not returned: %+v vs %+v", got, want)
19		}
20	}
