22	// TestResolveEvidenceCaps_LoadedFromYAML loads a real .ddx/config.yaml
23	// containing project-level caps and a per-harness override and verifies
24	// the resolved caps for each harness.
25	func TestResolveEvidenceCaps_LoadedFromYAML(t *testing.T) {
26		tmp := t.TempDir()
27		if err := os.MkdirAll(filepath.Join(tmp, ".ddx"), 0o755); err != nil {
28			t.Fatal(err)
29		}
30		yaml := `version: "1.0"
31	library:
32	  path: .ddx/plugins/ddx
33	  repository:
34	    url: https://github.com/DocumentDrivenDX/ddx-library
35	    branch: main
36	evidence_caps:
37	  max_prompt_bytes: 1000
38	  max_diff_bytes: 500
39	  per_harness:
40	    reviewer:
41	      max_prompt_bytes: 200
42	    grader:
43	      max_diff_bytes: 100
44	`
45		if err := os.WriteFile(filepath.Join(tmp, ".ddx", "config.yaml"), []byte(yaml), 0o600); err != nil {
46			t.Fatal(err)
47		}
48	
49		loader, err := NewConfigLoaderWithWorkingDir(tmp)
50		if err != nil {
51			t.Fatal(err)
52		}
53		cfg, err := loader.LoadConfig()
54		if err != nil {
55			t.Fatal(err)
56		}
57	
58		if cfg.EvidenceCaps == nil {
59			t.Fatal("EvidenceCaps not populated")
60		}
61	
62		// Default harness: project-level overrides only.
63		caps := cfg.ResolveEvidenceCaps("")
64		if caps.MaxPromptBytes != 1000 {
65			t.Errorf("project MaxPromptBytes = %d, want 1000", caps.MaxPromptBytes)
66		}
67		if caps.MaxDiffBytes != 500 {
68			t.Errorf("project MaxDiffBytes = %d, want 500", caps.MaxDiffBytes)
69		}
70		if caps.MaxInlinedFileBytes != evidence.DefaultMaxInlinedFileBytes {
71			t.Errorf("unset cap not at default: %d", caps.MaxInlinedFileBytes)
72		}
73	
74		// Reviewer override wins for MaxPromptBytes; project still applies elsewhere.
75		caps = cfg.ResolveEvidenceCaps("reviewer")
76		if caps.MaxPromptBytes != 200 {
77			t.Errorf("reviewer MaxPromptBytes = %d, want 200", caps.MaxPromptBytes)
78		}
79		if caps.MaxDiffBytes != 500 {
80			t.Errorf("reviewer MaxDiffBytes = %d, want 500 (project layer)", caps.MaxDiffBytes)
81		}
82	
83		// Grader override applies to MaxDiffBytes only.
84		caps = cfg.ResolveEvidenceCaps("grader")
85		if caps.MaxDiffBytes != 100 {
86			t.Errorf("grader MaxDiffBytes = %d, want 100", caps.MaxDiffBytes)
87		}
88		if caps.MaxPromptBytes != 1000 {
89			t.Errorf("grader MaxPromptBytes = %d, want 1000 (project layer)", caps.MaxPromptBytes)
90		}
91	}
